#include<bits/stdc++.h>
#define LL long long
using namespace std;
const int N = 1e5+5;
LL T,n,m,fa[N],Rt1,Rtn,ans;
LL a[N],b[N],cnta,cntb,f[N],g[N];
int FF(int u){return (fa[u]==u?u:fa[u]=FF(fa[u]));}
int main(){
    cin>>T;
    while(T--){
        cin>>n>>m;
        for(int i=1;i<=n;i++)fa[i]=i;
        for(int i=1;i<=m;i++){int x,y;cin>>x>>y;x=FF(x),y=FF(y);if(x!=y)fa[x]=y;}
        Rt1=FF(1),Rtn=FF(n),cnta=0,cntb=0;
        for(int i=1;i<=n;i++)if(FF(i)==Rt1)a[++cnta]=i;else if(FF(i)==Rtn)b[++cntb]=i;else;
        for(int i=1;i<=n;i++)f[i]=0x3f3f3f3f3f3f3f3f,g[i]=0x3f3f3f3f3f3f3f3f;f[Rt1]=0,g[Rtn]=0;
        for(int i=1;i<=n;i++){
            int u=FF(i);
            if(u!=Rt1){
                int id=upper_bound(a+1,a+cnta+1,i)-a-1;
                f[u]=min(f[u],1ll*(i-a[id])*(i-a[id]));
                if(id<cnta)++id,f[u]=min(f[u],1ll*(i-a[id])*(i-a[id]));
            }
            if(u!=Rtn){
                int id=upper_bound(b+1,b+cntb+1,i)-b;
                g[u]=min(g[u],1ll*(i-b[id])*(i-b[id]));
                if(id>1)--id,g[u]=min(g[u],1ll*(i-b[id])*(i-b[id]));
            }
        }
        ans=1ll*(n-1)*(n-1);
        for(int i=1;i<=n;i++)ans=min(ans,f[FF(i)]+g[FF(i)]);
        cout<<ans<<"\n";
    }
    return 0;
}
